pure fn add_service(amount: Number, rate: Number) -> Number {
    return amount + amount * rate
}
pure fn add_vat(amount: Number, rate: Number) -> Number {
    return amount + amount * rate
}
pure fn split_evenly(total: Number, n: Number) -> Number {
    return total / n
}
entry main(x: Text) {
    base = 30000
    after_service = add_service(base, 0.10)
    after_vat = add_vat(after_service, 0.10)
    per_person = split_evenly(after_vat, 4)
    return to_text(per_person)
}

pure fn apply_pct_discount(price: Number, rate: Number) -> Number {
    return price - price * rate
}
pure fn apply_coupon(price: Number, coupon: Number) -> Number {
    return price - coupon
}
pure fn apply_vat(price: Number, rate: Number) -> Number {
    return price + price * rate
}
entry main(x: Text) {
    base = 50000
    after_member = apply_pct_discount(base, 0.10)
    after_coupon = apply_coupon(after_member, 5000)
    final_price = apply_vat(after_coupon, 0.10)
    return to_text(final_price)
}

pure fn end_hour(start: Number, duration: Number) -> Number {
    return (start + duration) % 24
}
entry main(x: Text) {
    return to_text(end_hour(9, 26))
}

pure fn convert_to_krw(usd: Number, rate: Number) -> Number {
    return usd * rate
}
pure fn ceil_to_unit(amount: Number, unit: Number) -> Number {
    return ceil(amount / unit) * unit
}
entry main(x: Text) {
    krw = convert_to_krw(87.5, 1340)
    rounded = ceil_to_unit(krw, 100)
    return to_text(rounded)
}

pure fn sum_of(scores: Text) -> Number {
    total = 0
    for s in scores { total = total + s }
    return total
}
pure fn avg_drop_lowest(scores: Text) -> Number {
    lowest = min(scores)
    total = sum_of(scores)
    n = length(scores) - 1
    return (total - lowest) / n
}
entry main(x: Text) {
    scores = [85, 92, 78, 95, 88]
    return to_text(avg_drop_lowest(scores))
}
